mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM region_code
    WHERE region_code = #{regionCode}
)

SELECT EXISTS(
    SELECT 1
    FROM favorite_area
    WHERE member_id = #{memberId}
      AND region_code = #{regionCode}
)

mapper.insert:
INSERT INTO favorite_area (
    member_id,
    region_code
) VALUES (
    #{memberId},
    #{regionCode}
)

mapper.select:
SELECT member_id
FROM favorite_area
WHERE favorite_id = #{favoriteId}

mapper.delete:
DELETE FROM favorite_area
WHERE favorite_id = #{favoriteId}
  AND member_id = #{memberId}
